using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelTrainer
{
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger)
    {
        _logger = logger;
    }

    public (string report, string[] labels) TrainAndSave(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        ITransformer model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var report = $"""
            ========== Model Evaluation Metrics ==========
            MacroAccuracy:    {metrics.MacroAccuracy:F4}
            MicroAccuracy:    {metrics.MicroAccuracy:F4}
            LogLoss:          {metrics.LogLoss:F4}
            LogLossReduction: {metrics.LogLossReduction:F4}
            ===============================================
            """;

        _logger.LogInformation(report);
        _logger.LogInformation("Confusion matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Extract label ordering from the Score column slot names
        var scoreColumn = predictions.Schema["Score"];
        var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        _logger.LogInformation("Label order in Score column: {Labels}", string.Join(", ", labels));

        mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return (report, labels);
    }
}

